INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('017d1fc8-1afd-10bd-1b80-0f751c7a3085','vi','description','Blind Corner là một nhà máy rượu gia đình được chứng nhận Hữu cơ và Sinh thái tại Quindalup, phía bắc Margaret River. Được Ben và Naomi Gould thành lập cách đây 20 năm, nơi đây chuyên sản xuất các loại rượu tự nhiên can thiệp tối thiểu, bao gồm rượu vang sủi, vang trắng, vang cam/tiếp xúc vỏ, vang đỏ và không chất bảo quản. Quán Bar Nature theo mùa của họ mang đến một không gian thư giãn, thân thiện với gia đình và thú cưng, với tầm nhìn ra vườn nho hướng về phía rặng núi Yallingup. Tại đây phục vụ rượu vang hữu cơ và bia hữu cơ sản xuất tại chỗ, cùng với đồ ăn nhẹ.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('017d1fc8-1afd-10bd-1b80-0f751c7a3085','vi','famous_for','Rượu vang tự nhiên can thiệp tối thiểu, hữu cơ và sinh thái, nông nghiệp tái sinh, với nhà máy bia vi mô tại chỗ và quầy Bar Nature thư giãn.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('017d1fc8-1afd-10bd-1b80-0f751c7a3085','zh-Hans','description','Blind Corner 是一家位于昆达拉普的有机和生物动力法认证的家族酒庄，位于玛格丽特河北端。由 Ben 和 Naomi Gould 夫妇创立于20年前，专注于酿造低干预的天然葡萄酒，包括香槟、白葡萄酒、橙酒/皮接触酒、红酒和无防腐剂酒款。他们的季节性酒吧 Bar Nature 提供悠闲的环境，适合家庭和宠物犬，享有通往 Yallingup 山脊的葡萄园美景。这里供应有机葡萄酒和现场酿造的小批量有机啤酒，搭配各种小吃。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('017d1fc8-1afd-10bd-1b80-0f751c7a3085','zh-Hans','famous_for','有机和生物动力法认证的天然葡萄酒，修复性农业，现场微酿啤酒厂和休闲的 Bar Nature 酒窖。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('0220379d-36c2-41b8-34e2-762538e27955','vi','description','Xanadu Wines là một điền trang thuộc sở hữu gia đình tại Margaret River, được thành lập năm 1977 và mua lại bởi gia đình Rathbone vào năm 2005. Cửa hàng hầm rượu mở cửa hàng ngày, nơi bạn có thể thưởng thức rượu vang trong khi ngắm nhìn vườn nho. Nhà hàng tại chỗ kết hợp sản phẩm tươi ngon từ vùng Tây Nam với truyền thống Ý, tạo nên sự kết hợp hoàn hảo với các loại rượu của điền trang. Trải nghiệm nếm thử rượu bao gồm từ Vinework Tasting giá 15 đô đến Museum Flagship Tasting giá 50 đô, kèm theo khay phô mai và thịt nguội.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('0220379d-36c2-41b8-34e2-762538e27955','vi','famous_for','Cabernet Sauvignon đoạt giải quốc tế - rượu Cabernet 2023 được vinh danh là Rượu Vang Xuất Sắc nhất tại National Wine Show of Australia và xếp hạng #1 rượu vang đỏ thế giới tại International Wine & Spirit Competition.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('0220379d-36c2-41b8-34e2-762538e27955','zh-Hans','description','Xanadu Wines 是一家位于 Margaret River 的家族酒庄，始建于1977年，并于2005年被Rathbone家族收购。酒庄设有酒窖门市，游客可以在此一边品尝美酒，一边欣赏葡萄园美景。现场餐厅将西南地区食材与意大利传统完美结合，与酒庄美酒相得益彰。品酒体验从15美元的Vinework Tasting到50美元的Museum Flagship Tasting不等，另有奶酪和肉类拼盘可供选择。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('0220379d-36c2-41b8-34e2-762538e27955','zh-Hans','famous_for','国际大奖得主——其2023年份Cabernet Sauvignon被澳大利亚国家葡萄酒展评为最佳酒款，并在国际葡萄酒与烈酒大赛中荣获全球红酒第一。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('11111111-1111-1111-1111-111111111111','vi','description','Được thành lập vào năm 1967, Vasse Felix là điền trang rượu vang đầu tiên của Margaret River, nơi lưu giữ những cây nho nguyên thủy của khu vực và được gia đình Holmes a Court quản lý từ năm 1987. Du khách có thể nếm thử các loại rượu vang hiện tại tại quầy bar, thư giãn tại Wine Lounge hiện đại nhìn ra Home Vineyard, tham quan bảo tàng rượu The Vault và thưởng thức ẩm thực tại nhà hàng nổi tiếng ngay trong khuôn viên.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('11111111-1111-1111-1111-111111111111','vi','famous_for','Điền trang rượu vang đầu tiên của Margaret River, nổi tiếng với Cabernet Sauvignon và Chardonnay, đặc biệt là dòng Heytesbury.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('11111111-1111-1111-1111-111111111111','zh-Hans','description','创立于1967年的Vasse Felix是Margaret River的首家葡萄酒庄园，自1987年以来由Holmes a Court家族精心管理。游客可以在品酒吧品尝当季佳酿，或在俯瞰Home Vineyard的现代酒廊放松身心，还可参观The Vault葡萄酒博物馆，并在备受赞誉的餐厅享用美食。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('11111111-1111-1111-1111-111111111111','zh-Hans','famous_for','Margaret River的创始酒庄，以Cabernet Sauvignon和Chardonnay闻名，尤其是Heytesbury系列。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('1b5e3afb-da62-c8a2-c13c-f259f5c1039d','vi','description','Evoi Wines là một nhà máy rượu boutique tại Margaret River, tọa lạc tại 529 Osmington Rd, Bramley, được sáng lập vào năm 2007 bởi người làm rượu tận tụy Nigel Ludlow, bắt đầu với hai thùng Chardonnay. Phòng thử rượu nằm trong vườn nho đang hoạt động, có bãi cỏ rộng và khu vui chơi cho trẻ em, chỉ phục vụ các loại rượu Reserve sản xuất với số lượng nhỏ ngay tại chỗ.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('1b5e3afb-da62-c8a2-c13c-f259f5c1039d','vi','famous_for','Rượu vang Chardonnay tinh tế từ nhà máy rượu đạt chuẩn 5 sao đỏ Halliday; được vinh danh là Nhà máy rượu của năm Tây Úc tại Triển lãm Rượu Quốc tế Melbourne 2015 và được công nhận trong Giải thưởng Phòng thử rượu của Gourmet Traveller.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('1b5e3afb-da62-c8a2-c13c-f259f5c1039d','zh-Hans','description','Evoi Wines是一家位于Margaret River的精品酒庄，坐落在Bramley的529 Osmington Rd，由热情的酿酒师Nigel Ludlow于2007年创立，他从两桶Chardonnay开始创业。酒庄的品酒室坐落在一个仍在运作的葡萄园中，拥有宽敞的草坪和儿童游乐设施，仅在此地提供小批量珍藏酒款。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('1b5e3afb-da62-c8a2-c13c-f259f5c1039d','zh-Hans','famous_for','以Chardonnay为主的精品酒庄，获评5红星Halliday酒庄，并在2015年墨尔本国际葡萄酒展上被评为西澳年度酒庄，荣登《Gourmet Traveller》酒庄门奖。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('22222222-2222-2222-2222-222222222222','vi','description','Được thành lập năm 1971, đây là một điền trang thuộc sở hữu gia đình và đã qua ba thế hệ, áp dụng phương pháp sinh học động lực và trung hòa carbon. Tại Phòng Rượu Sinh Học Động Lực, bạn có thể thưởng thức các loại rượu Cabernet Sauvignon và Chardonnay của điền trang. Hơn 90% nguyên liệu trong thực đơn cố định của nhà hàng được trồng tại vườn sinh học động lực ngay trong khuôn viên.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('22222222-2222-2222-2222-222222222222','vi','famous_for','Tiên phong trong sản xuất rượu sinh học động lực Margaret River và nổi tiếng với các loại rượu biểu tượng Diana Madeline (Cabernet) và Kevin John (Chardonnay).',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('22222222-2222-2222-2222-222222222222','zh-Hans','description','创立于1971年的家族经营酒庄，现已传至第三代，采用生物动力法及碳中和实践。在生物动力酒室内，您可品尝到酒庄自酿的Cabernet Sauvignon和Chardonnay。酒庄餐厅的套餐菜单中，超过90%的食材取自于其现场的生物动力花园。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('22222222-2222-2222-2222-222222222222','zh-Hans','famous_for','玛格丽特河生物动力酿酒的先锋，标志性葡萄酒Diana Madeline（Cabernet）和Kevin John（Chardonnay）。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('31378e5f-07d1-217b-36e6-af243908afda','vi','description','Bettenays là một điền trang vườn nho đơn lẻ do gia đình sở hữu, được thành lập bởi Greg và Terri Bettenay vào năm 1989. Nơi đây kết hợp các loại rượu vang hảo hạng được sản xuất với sự can thiệp tối thiểu cùng với món kẹo nougat nổi tiếng của Margaret River, tất cả đều được sản xuất tại chỗ. Du khách có thể thưởng thức kẹo nougat miễn phí với cửa sổ nhìn vào bếp làm kẹo, cùng với một nhà hàng bên hồ để dùng bữa trưa.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('31378e5f-07d1-217b-36e6-af243908afda','vi','famous_for','Kẹo nougat Margaret River kết hợp cùng rượu vang điền trang',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('31378e5f-07d1-217b-36e6-af243908afda','zh-Hans','description','Bettenays酒庄由Greg和Terri Bettenay于1989年创立，是一家家族经营的单一葡萄园酒庄。这里精心酿造的优质葡萄酒采用最少干预的方式，与其著名的玛格丽特河牛轧糖完美搭配，所有产品均在酒庄内生产。游客可以免费品尝牛轧糖，并通过观景窗一窥牛轧糖厨房的制作过程，还可以在湖畔小餐馆享用午餐。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('31378e5f-07d1-217b-36e6-af243908afda','zh-Hans','famous_for','玛格丽特河牛轧糖与酒庄美酒的完美结合',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('33333333-3333-3333-3333-333333333333','vi','description','Fraser Gallop Estate được thành lập vào năm 1999 bởi Nigel Gallop tại thung lũng Wilyabrup của Margaret River. Đây là một điền trang có vườn nho đơn, canh tác khô, sản xuất rượu vang tinh tế từ nho trồng tại chỗ dưới bàn tay của nhà sản xuất rượu Ellin Tritt. Phòng thử rượu mở cửa hàng ngày với các buổi thử rượu được tuyển chọn kỹ lưỡng, cùng với tour "Rượu vang & Vườn nho" theo mùa khám phá khu vườn và khối nho bằng xe điện năng lượng mặt trời kèm khay phô mai.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('33333333-3333-3333-3333-333333333333','vi','famous_for','Rượu vang vườn nho đơn Wilyabrup trồng tại điền trang nổi tiếng với độ chính xác và thuần khiết, đặc biệt là Parterre Chardonnay (Giải thưởng Decanter World Wine Awards Best in Show) và Palladian Cabernet Sauvignon với đánh giá 5 sao từ James Halliday.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('33333333-3333-3333-3333-333333333333','zh-Hans','description','Fraser Gallop Estate坐落于玛格丽特河的Wilyabrup山谷，由Nigel Gallop于1999年创立。这座酒庄独具特色，专注于干耕种植，由酿酒师Ellin Tritt精心酿制出精确而纯净的葡萄酒。酒庄的品鉴室每天提供精心策划的品酒体验，并设有季节性的“葡萄酒与葡萄园之旅”，乘坐太阳能车探索花园和葡萄园，配有芝士拼盘，享受全方位的美酒之旅。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('33333333-3333-3333-3333-333333333333','zh-Hans','famous_for','以精准和纯净著称的Wilyabrup单一葡萄园酒，尤其是Parterre Chardonnay（Decanter世界葡萄酒大赛最佳展品）和Palladian Cabernet Sauvignon，荣获詹姆斯·哈利戴5星评级。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('36716a04-29bc-98e3-1fcd-f2e7602e02e7','vi','description','3 Oceans là một điền trang gia đình tại khu vực Margaret River, chuyên sản xuất một loạt rượu vang nhỏ (dòng Explorers và Lost Dogs) từ vườn nho của chính mình ở Margaret River và Frankland River. Địa điểm rộng lớn tại Cowaramup (trước đây là nhà máy rượu Palandri) có một cửa hàng rượu và quán café trong nhà máy, thân thiện với gia đình, và tổ chức các sự kiện âm nhạc trực tiếp suốt năm.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('36716a04-29bc-98e3-1fcd-f2e7602e02e7','vi','famous_for','Cửa hàng rượu lớn và quán café trong nhà máy, nổi tiếng với "Khay rượu cho hai người" và dòng rượu vang Explorers và Lost Dogs của chính điền trang.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('36716a04-29bc-98e3-1fcd-f2e7602e02e7','zh-Hans','description','3 Oceans 是位于玛格丽特河地区的一家家族酒庄，专注于小批量生产的葡萄酒，包括 Explorers 和 Lost Dogs 系列，原料来自玛格丽特河和弗兰克兰河的自有葡萄园。坐落在科沃拉姆普的宽敞场馆（前身为 Palandri 酒庄）设有品酒室和适合家庭的酒庄咖啡馆，并全年举办现场音乐活动。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('36716a04-29bc-98e3-1fcd-f2e7602e02e7','zh-Hans','famous_for','宽敞的品酒室和酒庄咖啡馆，以其“二人葡萄酒拼盘”而闻名，还有自家出产的 Explorers 和 Lost Dogs 葡萄酒系列。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('44444444-4444-4444-4444-444444444444','vi','description','Woodlands được thành lập vào lễ Phục Sinh năm 1973 bởi David và Heather Watson, là một trong năm vườn nho đầu tiên của khu vực Margaret River, vẫn do gia đình sở hữu qua nhiều thế hệ. Nằm tại điền trang Wilyabrup được chứng nhận hữu cơ, nơi đây sản xuất các loại rượu vang Cabernet pha trộn kiểu Bordeaux và Chardonnay cao cấp. Phòng thử rượu của họ cung cấp các buổi thử rượu có hướng dẫn miễn phí kéo dài ít nhất 45 phút, cùng với một khay phô mai quốc tế, thịt nguội địa phương và bánh mì focaccia nhà làm, mang đến trải nghiệm ẩm thực tinh tế.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('44444444-4444-4444-4444-444444444444','vi','famous_for','Cabernet Sauvignon trồng tại điền trang và các pha trộn kiểu Bordeaux cao cấp; một gia đình tiên phong tại Margaret River.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('44444444-4444-4444-4444-444444444444','zh-Hans','description','Woodlands酒庄由David和Heather Watson于1973年复活节创立，是玛格丽特河地区最早的五个葡萄园之一，至今仍由家族世代经营。酒庄位于获得有机认证的Wilyabrup庄园，以生产顶级的波尔多风格的赤霞珠混酿和霞多丽而闻名。酒窖为客人提供至少45分钟的免费导赏式座位品酒，搭配国际奶酪、本地熟食和自制佛卡夏面包共享拼盘，给您带来非凡的味觉体验。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('44444444-4444-4444-4444-444444444444','zh-Hans','famous_for','顶级庄园赤霞珠和波尔多风格混酿；玛格丽特河的先锋家族酒庄。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('49e41adf-d8bc-e9ef-9158-f33022a104ce','vi','description','Nằm tại Rosa Glen, đây là một điền trang nhỏ theo phương pháp sinh học động lực học do cặp đôi Sarah Morris và Iwo Jakimowicz sáng lập vào năm 2010. Với cách tiếp cận can thiệp tối thiểu, các buổi nếm thử rượu tại đây mang lại cảm giác thân mật và cần đặt lịch hẹn trước. Chuyến tham quan và nếm thử rượu kéo dài một giờ sẽ đưa khách dạo quanh vườn nho trồng khô và vườn rau sinh học động lực học trước khi tham gia buổi nếm thử có hướng dẫn. Những chú chó ngoan ngoãn có dây dắt và trẻ em (có sân chơi) đều được chào đón.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('49e41adf-d8bc-e9ef-9158-f33022a104ce','vi','famous_for','Rượu vang tự nhiên, được chứng nhận DEMETER, trồng từ chính điền trang, mang đậm hương vị địa phương (dòng Halcyon từ dây nho lâu năm và dòng Sauce dễ thưởng thức)',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('49e41adf-d8bc-e9ef-9158-f33022a104ce','zh-Hans','description','这是一座位于Rosa Glen的小型生物动力酒庄，由Sarah Morris和Iwo Jakimowicz夫妇于2010年创立。这里采用最少干预的酿酒方式，品酒体验亲密且需预约。酒庄提供一小时的生物动力农场之旅与品鉴，带领客人漫步于干旱生长的家庭葡萄园和生物动力菜园，然后进行专业导赏品酒。酒庄欢迎牵绳的乖巧宠物狗和孩子（设有游乐场）。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('49e41adf-d8bc-e9ef-9158-f33022a104ce','zh-Hans','famous_for','自然风味，DEMETER认证的生物动力酒庄自种葡萄酒，真正展现风土（包括来自老藤的Halcyon系列和易饮的Sauce系列）',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('5c8e4e4b-601e-70f2-3c90-3eb9bcacbf3d','vi','description','Wills Domain là một điền trang thuộc sở hữu của gia đình Haunold, nằm ở thung lũng Gunyulgup tại Yallingup, với những vườn nho ngập nắng hướng đến Ấn Độ Dương, một cửa hàng rượu thân thiện và nhà hàng nổi tiếng được đánh giá cao. Hai vườn nho cổ thụ được thành lập từ năm 1992 cung cấp trái nho cho các loại rượu vang của điền trang, bao gồm Cabernet, Shiraz, Chardonnay và rượu sủi tăm của điền trang.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('5c8e4e4b-601e-70f2-3c90-3eb9bcacbf3d','vi','famous_for','Được đánh giá 5 sao đỏ Halliday và nhà hàng fine-dining nhiều giải thưởng, được coi là một trong những nhà hàng cao cấp hàng đầu tại Margaret River.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('5c8e4e4b-601e-70f2-3c90-3eb9bcacbf3d','zh-Hans','description','Wills Domain是一处由Haunold家族拥有的庄园，坐落于Yallingup的Gunyulgup山谷。这里的葡萄园沐浴在阳光下，缓缓倾斜向印度洋，景色宜人。酒庄内有温馨的品酒室和备受赞誉的高档餐厅。1992年建立的两块老藤葡萄园为酒庄提供了出产佳酿的葡萄，包括Cabernet、Shiraz、Chardonnay以及庄园气泡酒。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('5c8e4e4b-601e-70f2-3c90-3eb9bcacbf3d','zh-Hans','famous_for','Halliday五星级评分和多帽精致餐厅，被誉为Margaret River区最佳高档餐厅之一。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('5d5bd129-3b5e-bb49-6605-6a6098ba8c72','vi','description','Marri Wood Park là một vườn nho nhỏ, do gia đình điều hành, được chứng nhận sinh học Demeter, được thành lập vào năm 1992 tại Yallingup. Nơi đây canh tác 16 mẫu nho không sử dụng hóa chất, thuốc trừ sâu, phân bón hoặc tưới tiêu. Quả nho được hái bằng tay, chọn lọc kỹ lưỡng và lên men trong các bình đất sét và thùng gỗ sồi để tạo ra những chai rượu vang từ vườn nho nhỏ lẻ độc quyền.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('5d5bd129-3b5e-bb49-6605-6a6098ba8c72','vi','famous_for','Nổi tiếng với rượu vang sinh học không hóa chất, được chứng nhận Demeter, từ vườn nho không tưới (bao gồm sauvignon blanc tiếp xúc với vỏ đầy phức tạp) và chuyến tham quan vườn nho sinh học có hướng dẫn miễn phí kèm nếm thử rượu và thưởng thức phô mai.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('5d5bd129-3b5e-bb49-6605-6a6098ba8c72','zh-Hans','description','Marri Wood Park是一家精品家族经营的葡萄园，坐落于雅林加普。自1992年成立以来，葡萄园获得Demeter认证，采用生物动力法种植，不使用任何化学品、杀虫剂、肥料或灌溉，悉心栽培的十六英亩葡萄藤。采摘和挑选的葡萄经过陶罐和橡木桶的精心发酵，酿造出小批量的庄园葡萄酒。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('5d5bd129-3b5e-bb49-6605-6a6098ba8c72','zh-Hans','famous_for','以Demeter认证的生物动力法酿造、无化学添加的干生长庄园葡萄酒（包括复杂口感的皮接触长相思）以及免费的生物动力葡萄园导览品酒和奶酪拼盘享誉盛名。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('67b423d3-54e3-48fa-3357-6b29bc976ccd','vi','description','Cửa hàng rượu vang của Howard Park tại Cowaramup mang dấu ấn kiến trúc độc đáo, lấy cảm hứng từ phong thủy, nằm giữa khu rừng tự nhiên. Khu vườn xanh mướt, chăn dã ngoại và trò chơi trên cỏ tạo không gian vui chơi cho cả gia đình và những chú chó. Wine Chapel riêng tư mang đến trải nghiệm gần gũi dưới ánh đèn chùm làm từ những cây nho 45 năm tuổi, kết hợp với phô mai và thịt nguội địa phương.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('67b423d3-54e3-48fa-3357-6b29bc976ccd','vi','famous_for','Rượu vang sủi bọt truyền thống và rượu vang điền trang từ Margaret River và Great Southern, được xếp hạng 5 sao Halliday cùng với Wine Chapel sang trọng riêng tư.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('67b423d3-54e3-48fa-3357-6b29bc976ccd','zh-Hans','description','Howard Park位于Cowaramup的独特酒窖门面融合了建筑艺术和风水理念，坐落在原生态的灌木丛中。这里设有草坪花园、野餐垫和草地游戏，户外区域欢迎家庭和宠物狗光临。私密的Wine Chapel则提供了一个独特的座位体验，在45年老藤制成的吊灯下，搭配本地奶酪和肉类冷盘，尽享美味。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('67b423d3-54e3-48fa-3357-6b29bc976ccd','zh-Hans','famous_for','传统法起泡酒及Margaret River与Great Southern地区的庄园葡萄酒，荣获5星Halliday评级与奢华的私人Wine Chapel。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('6878ef0b-b794-39dc-dfec-d6d7200d28e7','vi','description','Gralyn Estate là một nhà máy rượu do gia đình sở hữu thế hệ thứ hai, tọa lạc trên đường Caves ở Wilyabrup, khai trương vào năm 1975 và là nơi có cửa hầm rượu đầu tiên của Margaret River. Phòng nếm rượu hiện đại nhìn ra những vườn nho. Du khách có thể nếm thử miễn phí toàn bộ dòng rượu vang đơn vườn cao cấp và chủ sở hữu tổ chức trải nghiệm cao cấp giới hạn 90 phút, đưa khách từ vườn nho đến ly rượu và vào hầm rượu ngầm ban đầu để nếm thử các loại rượu bảo tàng có từ năm 1980.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('6878ef0b-b794-39dc-dfec-d6d7200d28e7','vi','famous_for','Rượu vang đỏ đơn vườn cao cấp và rượu tăng cường hiếm có chỉ có tại hầm rượu; Artizan tăng cường đoạt giải.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('6878ef0b-b794-39dc-dfec-d6d7200d28e7','zh-Hans','description','Gralyn Estate酒庄由家族第二代掌管，坐落于Wilyabrup的Caves Road上，自1975年开业以来，成为玛格丽特河地区首个酒庄开放点。现代化的品酒室俯瞰着葡萄园，游客可以免费品尝到全系列的优质单一葡萄园葡萄酒。酒庄主人还会提供限量的90分钟高端体验，从葡萄到酒杯，带领客人深入原始地下酒窖，品尝自1980年以来的博物馆藏酒。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('6878ef0b-b794-39dc-dfec-d6d7200d28e7','zh-Hans','famous_for','顶级单一葡萄园红酒和罕见的陈年加强酒，仅在酒庄开放点可得；屡获殊荣的Artizan加强酒。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('6be3229f-dc8c-8265-b76f-a0fa486fa504','vi','description','Một cửa hàng rượu vang hữu cơ được chứng nhận tại Wilyabrup mang lại cảm giác ấm cúng, nơi bạn có thể thưởng thức các loại rượu vang sản xuất nhỏ của điền trang qua các buổi thử nếm có hướng dẫn và thư giãn với đĩa phô mai và thịt nguội tự chọn trên thảm picnic trong vườn. Nơi đây thân thiện với chó, có trò chơi trên cỏ và khu vui chơi cho trẻ em, đồng thời chào đón thức ăn từ bên ngoài.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('6be3229f-dc8c-8265-b76f-a0fa486fa504','vi','famous_for','Rượu vang hữu cơ Margaret River độc đáo từ trái cây trồng tại điền trang, bao gồm các loại vang sủi bọt nhỏ như Petillant Naturel và Cremant.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('6be3229f-dc8c-8265-b76f-a0fa486fa504','zh-Hans','description','在Wilyabrup葡萄园中的这家温馨有机认证酒庄，您可以享受小批量庄园葡萄酒的导览品鉴，还可以在花园的野餐垫上享受自制的芝士和熟食拼盘。这里欢迎宠物犬，也有草坪游戏和儿童活动区，并且允许自带食物。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('6be3229f-dc8c-8265-b76f-a0fa486fa504','zh-Hans','famous_for','独具匠心的有机玛格丽特河葡萄酒，全部采用庄园自种葡萄酿制，包括小批量起泡酒如Petillant Naturel和Cremant。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('7097c5db-283a-6e0e-58ad-abd598d233e9','vi','description','Phòng thử rượu của Stella Bella nằm trên đường Rosa Brook, chỉ cách thị trấn Margaret River 4,6km, mang đến trải nghiệm thử rượu đặc biệt với sự hướng dẫn của những người dẫn dắt am hiểu. Du khách có thể thưởng thức rượu vang theo ly và mang theo bữa ăn dã ngoại để tận hưởng không khí xung quanh vườn nho.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('7097c5db-283a-6e0e-58ad-abd598d233e9','vi','famous_for','Nổi tiếng với rượu vang tinh tế vùng nam Margaret River, đặc biệt là Chardonnay đoạt giải thưởng; có sáu loại rượu trong Top 100 năm 2026, nhiều hơn bất kỳ nhà máy rượu nào khác ở Tây Úc.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('7097c5db-283a-6e0e-58ad-abd598d233e9','zh-Hans','description','Stella Bella酒庄的品酒室位于Rosa Brook Road上，距离玛格丽特河镇仅4.6公里。这里的品酒体验由经验丰富的讲解员带领，深入探索南玛格丽特河地区的佳酿。游客可以在此品尝杯装葡萄酒，并自带野餐，享受葡萄园的独特风景。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('7097c5db-283a-6e0e-58ad-abd598d233e9','zh-Hans','famous_for','以精致的南玛格丽特河佳酿闻名，特别是屡获殊荣的Chardonnay；2026年Top 100中有六款上榜，领先所有西澳酒庄。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('75208f29-0dc6-1580-78e6-9aa982e6a4a9','vi','description','Churchview Estate là một nhà máy rượu boutique thuộc sở hữu gia đình, với vườn nho đơn lẻ được chứng nhận hữu cơ tại Metricup. Tại đây, bạn có thể thưởng thức những loại rượu quý hiếm và cao cấp trong một căn nhà cổ điển có tầm nhìn ra vườn nho. Được xây dựng từ đầu vào năm 1999 bởi hai cha con Spike và Raymond Fokkema, nhà máy rượu trồng 16 giống nho trên diện tích 56 hecta vườn nho của điền trang.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('75208f29-0dc6-1580-78e6-9aa982e6a4a9','vi','famous_for','Rượu vang hữu cơ từ vườn nho đơn lẻ trong ngôi nhà cổ',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('75208f29-0dc6-1580-78e6-9aa982e6a4a9','zh-Hans','description','Churchview Estate是一家位于Metricup的精品家族酒庄，拥有经认证的有机单一葡萄园。在这里，您可以在一座古色古香的历史小屋中品味稀有和高端葡萄酒，窗外便是郁郁葱葱的葡萄藤。酒庄由父子二人Spike和Raymond Fokkema于1999年亲手创立，占地56公顷，种植了16个不同的葡萄品种。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('75208f29-0dc6-1580-78e6-9aa982e6a4a9','zh-Hans','famous_for','历史小屋中的有机单一葡萄园佳酿',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('773a08da-f201-c484-853b-cc5e693bcd5e','vi','description','McHenry Hohnen kết hợp cửa hàng rượu với Vintners Wine Bar tại Witchcliffe, nơi bạn có thể thưởng thức rượu vang từ vườn nho đơn canh theo phương pháp sinh học động lực và thực đơn chia sẻ theo mùa mang phong cách Địa Trung Hải, nổi bật với thịt cừu McHenry Farms và sản phẩm trồng tại điền trang. Không gian bao gồm khu vực ấm cúng trong nhà, khu vườn và sân chơi petanque.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('773a08da-f201-c484-853b-cc5e693bcd5e','vi','famous_for','Rượu vang từ vườn nho đơn canh theo phương pháp sinh học động lực, thể hiện trọn vẹn vùng đất Margaret River.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('773a08da-f201-c484-853b-cc5e693bcd5e','zh-Hans','description','McHenry Hohnen酒庄与位于Witchcliffe的Vintners Wine Bar完美结合。在这里，您可以品尝到生物动力法种植的单一葡萄园佳酿，同时享用一份充满地中海风情的时令共享菜单，特色菜包括McHenry Farms的优质羊肉和酒庄自产的新鲜食材。这里的环境舒适怡人，拥有温馨的室内空间、花园和一个法式滚球场。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('773a08da-f201-c484-853b-cc5e693bcd5e','zh-Hans','famous_for','生物动力法种植的单一葡萄园佳酿，纯粹展现Margaret River风土。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('786a007c-6447-c792-1c2d-c7eedcb1c80e','vi','description','Pierro là một điền trang gia đình tại Willyabrup do Tiến sĩ Michael Peterkin sáng lập, được biết đến là một trong những vườn nho trồng mật độ cao đầu tiên ở Margaret River. Phòng thử rượu ấm cúng của chúng tôi luôn chào đón du khách đến thưởng thức và khám phá dòng sản phẩm của Pierro. Các tour tham quan vườn nho và nhà máy rượu được tổ chức theo yêu cầu vào thứ Sáu hàng tuần.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('786a007c-6447-c792-1c2d-c7eedcb1c80e','vi','famous_for','Chardonnay Margaret River kiểu mẫu, sang trọng',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('786a007c-6447-c792-1c2d-c7eedcb1c80e','zh-Hans','description','Pierro酒庄由Michael Peterkin博士创立，是一家家族经营的Willyabrup庄园，也是Margaret River地区最早进行高密度葡萄种植的酒庄之一。酒庄的品酒室氛围温馨，欢迎访客品尝并了解Pierro的系列佳酿。每周五可预约参加定制的葡萄园和酒庄参观之旅。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('786a007c-6447-c792-1c2d-c7eedcb1c80e','zh-Hans','famous_for','Margaret River产区的典范Chardonnay',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('8023295f-0fda-e61e-8ff9-cf418ffe0f7d','vi','description','Leeuwin Estate là một nhà máy rượu gia đình tại Margaret River, được sáng lập vào năm 1973 bởi Denis và Tricia Horgan, hiện nay được điều hành bởi ba thế hệ của gia đình sáng lập. Được xây dựng quanh "Nghệ thuật Rượu vang Hảo hạng", nơi đây có hầm rượu trưng bày nghệ thuật, các buổi nếm thử rượu được tổ chức tinh tế và nhà hàng nổi tiếng. Các chai rượu Art Series của nơi này nổi bật với nhãn dán là tác phẩm của các nghệ sĩ đương đại Úc.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('8023295f-0fda-e61e-8ff9-cf418ffe0f7d','vi','famous_for','Art Series Chardonnay danh tiếng và trải nghiệm nghệ thuật kết hợp rượu vang',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('8023295f-0fda-e61e-8ff9-cf418ffe0f7d','zh-Hans','description','Leeuwin Estate 是一家位于玛格丽特河的家族酒庄，由Denis 和Tricia Horgan 于1973年创立，现由创始家族的三代人共同经营。酒庄以“精致葡萄酒的艺术”为核心，设有艺术画廊酒窖、精心策划的坐式品酒会以及备受赞誉的餐厅。其著名的Art Series系列酒标签上展现了澳大利亚当代艺术家的作品。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('8023295f-0fda-e61e-8ff9-cf418ffe0f7d','zh-Hans','famous_for','享誉国际的Art Series Chardonnay和艺术与美酒的完美体验',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('81c43507-fd2d-866e-7ce9-b3697ef1bb75','vi','description','Là một trong những điền trang rượu vang đầu tiên tại Margaret River, Voyager Estate được thành lập năm 1978 và vẫn thuộc sở hữu gia đình. Đây là một nhà sản xuất hữu cơ được chứng nhận, chuyên làm rượu từ 100% nho trồng tại điền trang. Nhà hàng nổi tiếng của điền trang phục vụ thực đơn nếm thử theo mùa gồm năm món, kết hợp với rượu vang của chính điền trang. Các buổi nếm thử có hướng dẫn tại Phòng Rượu vang, từ trải nghiệm thân mật Savour Voyager đến trải nghiệm sâu sắc Discover và Unearth, đều hứa hẹn đem lại những cảm nhận độc đáo.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('81c43507-fd2d-866e-7ce9-b3697ef1bb75','vi','famous_for','Chardonnay và Cabernet Sauvignon đẳng cấp thế giới từ điền trang hữu cơ 100% nho tự trồng, cùng với nhà hàng đạt giải thưởng (Nhà hàng Khu vực của Năm 2025 theo Hướng dẫn Ẩm thực Tốt Tây Úc).',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('81c43507-fd2d-866e-7ce9-b3697ef1bb75','zh-Hans','description','作为玛格丽特河地区的创始酒庄之一，Voyager Estate成立于1978年，至今仍由家族经营。酒庄拥有有机认证，出产100%自家葡萄酿制的优质葡萄酒。其著名餐厅提供五道菜的季节性品鉴菜单，并搭配酒庄精选佳酿。酒庄的品酒室提供多种导览品鉴，从私密的Savour Voyager到深度的Discover和Unearth体验，皆让人难忘。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('81c43507-fd2d-866e-7ce9-b3697ef1bb75','zh-Hans','famous_for','世界级的Chardonnay和Cabernet Sauvignon，来自100%自家葡萄种植的有机酒庄，以及屡获殊荣的酒庄餐厅（2025年西澳美食指南地区年度餐厅）。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('82dc2053-1d49-5227-9f95-7274a025727a','vi','description','Skigh Wine là một nhà sản xuất rượu vang nhỏ và tinh tế tại Margaret River. Tọa lạc trên những ngọn đồi Yallingup, vườn nho của họ được chứng nhận hữu cơ và sử dụng phương pháp lên men tự nhiên với men bản địa, hàm lượng lưu huỳnh thấp để tạo ra những dòng rượu vang tự nhiên, ít can thiệp. Phòng thử rượu nằm trong một kho thóc được cải tạo thoáng đãng, với khu vườn rộng lớn, nơi bạn có thể thưởng thức các dòng vang kinh điển của Margaret River như Chardonnay và Cabernet cùng với những lựa chọn khác như Tempranillo, Petit Verdot và Cabernet Franc.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('82dc2053-1d49-5227-9f95-7274a025727a','vi','famous_for','Rượu vang tự nhiên ít can thiệp từ vườn nho hữu cơ, thưởng thức trong không gian kho thóc thoải mái.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('82dc2053-1d49-5227-9f95-7274a025727a','zh-Hans','description','Skigh Wine 是一家位于玛格丽特河的精品酒庄，坐落在风景如画的Yallingup Hills。他们的葡萄园经过有机认证，采用自发的天然酵母发酵和低硫工艺，酿造出具有最小干预的天然葡萄酒。酒庄的品酒室是一个悠闲的改建谷仓，周围是绿意盎然的花园。在这里，您可以品尝到玛格丽特河的经典佳酿如Chardonnay和Cabernet，以及Tempranillo、Petit Verdot和Cabernet Franc等别具特色的葡萄酒。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('82dc2053-1d49-5227-9f95-7274a025727a','zh-Hans','famous_for','有机认证葡萄园的天然葡萄酒，悠闲的谷仓品酒体验。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('83a42af6-841d-a94d-07b9-83bb07c1d443','vi','description','Được thành lập vào năm 1985 tại Wilyabrup, Margaret River, đây là một điền trang sở hữu gia đình với vườn nho rộng 14 hecta. Chúng tôi cung cấp trải nghiệm thưởng thức rượu vang tại hầm rượu với hướng dẫn thư giãn, lên tới năm loại rượu với giá 15 đô la mỗi khách. Hầm rượu thân thiện với chó cũng phục vụ rượu vang theo ly cùng các món ăn nhẹ địa phương. Vào mùa hè, có nhà hàng Elliott''s tại Fermoy và chỗ nghỉ tại The Lodge ngay trong khuôn viên.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('83a42af6-841d-a94d-07b9-83bb07c1d443','vi','famous_for','Nổi tiếng với Cabernet Sauvignon và Chardonnay; rượu Reserve Cabernet Sauvignon đã giành giải ''Best in Show'' tại Decanter World Wine Awards 2024 và ''Platinum'' 2025.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('83a42af6-841d-a94d-07b9-83bb07c1d443','zh-Hans','description','这是一家成立于1985年的家族酒庄，位于玛格丽特河的Wilyabrup，占地14公顷的庄园葡萄园。我们提供轻松的导览酒窖品酒体验，每位客人可品尝多达五款葡萄酒，费用为每位15美元。狗友好的酒窖大门提供单杯葡萄酒和本地小食。夏季还有一间季节性餐厅（Elliott''s at Fermoy）以及The Lodge的现场住宿。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('83a42af6-841d-a94d-07b9-83bb07c1d443','zh-Hans','famous_for','以其著名的Cabernet Sauvignon和Chardonnay而闻名，其珍藏Cabernet Sauvignon在Decanter世界葡萄酒大奖中荣获2024年“最佳展出”和2025年“铂金”奖。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('8d99b646-1362-04a2-9efb-b2e4a0fbbae8','vi','description','Một điền trang nhỏ thuộc sở hữu gia đình tại Margaret River, được thành lập vào năm 2011 trên một khu đất có khu bảo tồn thiên nhiên dành cho loài thú có túi đuôi vòng phía tây đang nguy cấp. Các chuyến thăm là những trải nghiệm hướng dẫn thân mật trong phòng nếm rượu chuyên biệt, từ nếm thử có hướng dẫn với giá 10 đô la đến các buổi đi bộ riêng tư kết hợp giữa thiên nhiên và rượu vang, kèm theo phô mai, thịt nguội và sô-cô-la.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('8d99b646-1362-04a2-9efb-b2e4a0fbbae8','vi','famous_for','Rượu vang chất lượng cao, sản xuất bền vững với số lượng hạn chế — đặc biệt là ''La Joie'' Chenin Blanc sủi bọt theo phương pháp truyền thống và Cabernet Sauvignon đoạt giải thưởng.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('8d99b646-1362-04a2-9efb-b2e4a0fbbae8','zh-Hans','description','这是一家位于玛格丽特河的小型家族酒庄，成立于2011年，坐落在一个拥有灌木自然保护区的土地上，致力于保护濒危的西部环尾负鼠。参观者可享受专属品鉴室内的亲密导览体验，从10美元的导览品鉴到私人自然和葡萄酒漫步，均提供奶酪、熟食和巧克力糖果的搭配。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('8d99b646-1362-04a2-9efb-b2e4a0fbbae8','zh-Hans','famous_for','可持续生产的小批量葡萄酒——尤其是屡获殊荣的“La Joie”传统工艺起泡酒Chenin Blanc和获奖的Cabernet Sauvignon。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('99889e7f-0541-3e5e-9cc9-a0219ec9dcdd','vi','description','Windows Estate là một vườn nho gia đình nhỏ, được chứng nhận hữu cơ tại Yallingup ở vùng Margaret River, canh tác năm mảnh đất trên 15 mẫu với trọng tâm vào đa dạng sinh học, các phương pháp tái tạo và sản xuất rượu vang tinh tế, thủ công. Du khách có thể nếm thử tại cửa hầm rượu thân mật hoặc tham gia Chuyến tham quan & Nếm thử Vườn nho Hữu cơ do chủ sở hữu Chris hoặc Jo hướng dẫn, kết thúc bằng buổi nếm thử riêng tư với ly Zalto.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('99889e7f-0541-3e5e-9cc9-a0219ec9dcdd','vi','famous_for','Nghệ thuật làm rượu hữu cơ tinh tế',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('99889e7f-0541-3e5e-9cc9-a0219ec9dcdd','zh-Hans','description','Windows Estate是一家位于玛格丽特河Yallingup的小型有机认证家族葡萄园，占地15英亩，精心耕作五个地块，注重生物多样性、再生农业和温和手工酿酒。游客可以在温馨的酒窖门口品尝佳酿，或参加由主人Chris或Jo带领的有机葡萄园之旅和品酒活动，并在Zalto酒杯的陪伴下进行私人品鉴。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('99889e7f-0541-3e5e-9cc9-a0219ec9dcdd','zh-Hans','famous_for','精雕细琢的有机酿酒艺术',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('af6a0bbf-f27a-5a9c-5d10-5123a1e4665b','vi','description','Tọa lạc tại Wilyabrup, đây là một điền trang yên bình do gia đình sở hữu và điều hành, đã trải qua hơn 40 mùa vụ liên tiếp. Nơi đây mang đến trải nghiệm nếm rượu thư thái, có hướng dẫn tại hầm rượu với các loại rượu vang thượng hạng được chế tác thủ công từ nho trồng hoàn toàn tại điền trang. Tiện nghi dã ngoại có sẵn tại chỗ.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('af6a0bbf-f27a-5a9c-5d10-5123a1e4665b','vi','famous_for','Nổi tiếng với các loại rượu trắng Margaret River thanh nhã và tinh tế (Riesling, Semillon, Sauvignon Blanc, Verdelho, Chardonnay) cùng những chai rượu đoạt giải được James Halliday ca ngợi.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('af6a0bbf-f27a-5a9c-5d10-5123a1e4665b','zh-Hans','description','这是位于Wilyabrup的一家宁静的家族酒庄，已有超过40个年头的历史。酒庄提供轻松愉悦的向导式酒窖品鉴，让您品尝由100%庄园种植的葡萄酿制而成的优质单一葡萄园手工葡萄酒。现场还设有野餐设施，供您享受大自然的美好。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('af6a0bbf-f27a-5a9c-5d10-5123a1e4665b','zh-Hans','famous_for','以精致且低调的玛格丽特河白葡萄酒（如Riesling, Semillon, Sauvignon Blanc, Verdelho, Chardonnay）及获詹姆斯·哈利戴称赞的奖杯级别葡萄酒闻名。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('b1222f17-4b74-754c-fa56-5a5bfc96a463','vi','description','Nằm ở rìa Wilyabrup, vườn nho nhỏ do gia đình Robert và Emma Menzies sở hữu và điều hành. Họ trồng nho theo phương pháp mật độ cao (cây cách nhau chỉ một mét) và áp dụng nguyên tắc hữu cơ, toàn bộ nho đều được hái tay và lựa chọn kỹ lưỡng. Cửa hầm rượu cung cấp trải nghiệm nếm rượu tinh tế và thông tin, cùng chuyến tham quan đặc biệt phía sau hậu trường phòng ủ với Rob.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('b1222f17-4b74-754c-fa56-5a5bfc96a463','vi','famous_for','Rượu đỏ kiểu Bordeaux và Chardonnay từ vườn nho gia đình trồng mật độ cao.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('b1222f17-4b74-754c-fa56-5a5bfc96a463','zh-Hans','description','坐落于Wilyabrup边缘，这是一家由Robert和Emma Menzies家族经营的小型葡萄园。这里采用高密度种植（葡萄藤间距仅一米）和有机种植原则，所有葡萄均为手工采摘和精心挑选。酒窖提供精品的品鉴体验，并可由Rob亲自带领，深入了解酒桶室的幕后故事。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('b1222f17-4b74-754c-fa56-5a5bfc96a463','zh-Hans','famous_for','高密度种植的家族精品庄园波尔多风格红酒和Chardonnay。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('b4e8b6a2-851b-de47-31f3-68e53a0494e9','vi','description','Từ năm 1991, Edwards Wines đã được gia đình sở hữu và điều hành, hàng ngày phục vụ rượu vang từ vườn nho của mình tại hầm rượu ở Cowaramup, nơi chiếc máy bay Tiger Moth ''Matilda'' được phục hồi từ năm 1943 được trưng bày trang trọng. Du khách có thể thưởng thức rượu cùng các đĩa ăn địa phương cao cấp hoặc kết hợp với sô-cô-la thủ công, và nhà hàng Miss Chow''s ngay tại khuôn viên nhìn ra vườn nho.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('b4e8b6a2-851b-de47-31f3-68e53a0494e9','vi','famous_for','Rượu vang thủ công từ vườn nho và câu chuyện về máy bay Matilda Tiger Moth; chuyến bay lịch sử của người sáng lập Brian Edwards từ Anh đến Úc.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('b4e8b6a2-851b-de47-31f3-68e53a0494e9','zh-Hans','description','自1991年以来，Edwards Wines由家族经营，在Cowaramup的酒窖每天供应自家葡萄园出产的美酒。这里的一大亮点是经过修复的1943年Tiger Moth飞机“Matilda”。游客可以在享用当地美食拼盘或手工巧克力搭配酒品的同时，享受Miss Chow''s餐厅的美景，该餐厅俯瞰葡萄园。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('b4e8b6a2-851b-de47-31f3-68e53a0494e9','zh-Hans','famous_for','自家葡萄园手工酿制的美酒以及Matilda Tiger Moth的传奇故事；创始人Brian Edwards从英格兰飞抵澳大利亚的历史性飞行。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('bc30ab2c-95ed-c658-29dd-6d74521e7184','vi','description','Được thành lập vào năm 1992, cửa hầm rượu hiện đại của Hamelin Bay mở ra một sàn ngoài trời và bãi cỏ với tầm nhìn tuyệt đẹp ra những vườn nho, thung lũng, hồ và rừng tại vườn nho Five Ashes. Nhà hàng tại chỗ phục vụ bữa trưa theo mùa được chế biến từ nguyên liệu tươi ngon nhất của địa phương từ thứ Năm đến Chủ Nhật, cùng với các đĩa phô mai và thịt nguội hàng ngày.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('bc30ab2c-95ed-c658-29dd-6d74521e7184','vi','famous_for','Rượu vang thượng hạng từ vườn nho Five Ashes và bữa trưa ngắm cảnh vườn nho',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('bc30ab2c-95ed-c658-29dd-6d74521e7184','zh-Hans','description','成立于1992年的Hamelin Bay酒庄，现代化的酒窖大门通向露天平台和草坪，俯瞰Five Ashes葡萄园的迷人景色：藤蔓、山谷、湖泊和森林尽收眼底。酒庄内的餐厅每周四至周日供应以最新鲜本地食材制作的时令午餐，每天还提供精美的奶酪和熟食拼盘。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('bc30ab2c-95ed-c658-29dd-6d74521e7184','zh-Hans','famous_for','Five Ashes葡萄园的经典庄园美酒与美景午餐',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('bf7e6df5-5101-2569-ee7f-489c107f935e','vi','description','Cape Mentelle là một hầm rượu tiên phong tại Margaret River, toạ lạc tại 331 Wallcliffe Road, mở cửa hàng ngày. Khu vườn thư giãn với xích đu, bàn picnic và đường chơi petanque kiểu Pháp truyền thống. Các buổi thử rượu đa dạng từ trải nghiệm tại phòng nếm thử tới tour đi bộ riêng tư qua quy trình sản xuất rượu, kết thúc tại hầm Cabernet bằng đất nện với buổi hướng dẫn kết hợp rượu và ẩm thực.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('bf7e6df5-5101-2569-ee7f-489c107f935e','vi','famous_for','Nhà máy rượu sáng lập tại Margaret River nổi tiếng với Cabernet Sauvignon chuẩn mực (đã giành giải Jimmy Watson).',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('bf7e6df5-5101-2569-ee7f-489c107f935e','zh-Hans','description','Cape Mentelle 是位于玛格丽特河的先锋酒庄，坐落在Wallcliffe路331号，每天开放。酒庄环境宁静，设有秋千、野餐桌以及传统法式滚球道。品酒体验多样，从品酒室体验到私人步行游览，最后在夯土建造的Cabernet酒窖内进行葡萄酒与美食的专业搭配。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('bf7e6df5-5101-2569-ee7f-489c107f935e','zh-Hans','famous_for','Margaret River创始酒庄，以其标志性的Cabernet Sauvignon（Jimmy Watson奖得主）而闻名。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('c22cbb53-a339-8a7b-6115-3128656645ce','vi','description','Một cửa hàng bán rượu vang thân thiện và thoải mái bên dòng suối Calgardup ở Margaret River, được bao quanh bởi rừng và vườn nho với tầm nhìn ra hồ và hoàng hôn. Người sáng lập Robert Gherardi phục vụ rượu vang thủ công nhấn mạnh sự tinh khiết của trái cây, sự cân bằng và thanh lịch. Thử rượu bắt đầu từ $10 cho dòng sản phẩm chính, với tour tham quan nhà máy rượu vang "Nếm Truyền Thống" hàng ngày và đĩa ăn nhẹ, cùng với xe thức ăn mang cảm hứng Ý CIBO tại chỗ.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('c22cbb53-a339-8a7b-6115-3128656645ce','vi','famous_for','Phong cách làm rượu truyền thống Margaret River với ảnh hưởng Ý, đặc biệt là Cabernet Sauvignon qua nhãn LIRICA.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('c22cbb53-a339-8a7b-6115-3128656645ce','zh-Hans','description','在玛格丽特河畔的Calgardup Brook旁，有一个悠闲而热情的酒窖门市，被森林和葡萄园环绕，坐拥湖泊和日落美景。创始人Robert Gherardi在这里亲手斟酌手工酿制的葡萄酒，强调果香的纯净、平衡与优雅。品酒会从核心系列起价10美元，提供每日“品味传统”酒庄之旅和品尝拼盘，现场还有意大利风味的CIBO餐车。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('c22cbb53-a339-8a7b-6115-3128656645ce','zh-Hans','famous_for','意大利风味的经典玛格丽特河酿酒，特别是LIRICA系列的Cabernet Sauvignon。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('c60a5b7c-8a29-51e8-4c23-0a945033ad64','vi','description','Glenarty Road là một trang trại gia đình năm thế hệ tại Karridale (miền nam Margaret River) cung cấp trải nghiệm ẩm thực từ nông trại đến bàn ăn, rượu vang trồng tại điền trang được làm theo phương pháp tự nhiên và một quầy bar rượu phục vụ thịt nguội, phô mai và bánh mì mới nướng tự làm. Các trải nghiệm đa dạng từ thử rượu truyền thống $15 đến dạo bộ trong vườn, tham quan trang trại tái tạo và bữa tiệc rượu vang giữa vườn nho.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('c60a5b7c-8a29-51e8-4c23-0a945033ad64','vi','famous_for','Ẩm thực tái tạo từ nông trại đến bàn ăn — được vinh danh là Điểm đến Ẩm thực Tốt nhất Úc (Gourmet Traveller, 2023)',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('c60a5b7c-8a29-51e8-4c23-0a945033ad64','zh-Hans','description','Glenarty Road 是位于玛格丽特河南部 Karridale 的一个拥有五代传承的家族农场。这里提供从农场到餐桌的用餐体验，采用自然手法酿造的庄园葡萄酒，以及供应自制腌肉、奶酪和新鲜烘焙面包的酒吧。您可以选择从传统的$15品酒会到花园漫步、再生农场之旅，以及在葡萄园中漫游的盛宴等多种体验。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('c60a5b7c-8a29-51e8-4c23-0a945033ad64','zh-Hans','famous_for','从农场到餐桌的再生美食——荣获《Gourmet Traveller》2023年澳大利亚最佳目的地餐饮称号',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('d1239ea2-d792-43c7-06b1-dd65a8b5e269','vi','description','Yeah Wine là một nhà sản xuất rượu quy mô nhỏ thuộc sở hữu gia đình, do Sian và Andrew Dawson điều hành. Họ tự tay sản xuất, đóng chai và dán nhãn hơn hai mươi loại rượu từ các nhà trồng nho khắp Tây Úc. Cửa hàng hầm rượu mộc mạc của họ tại 401 Wallcliffe Rd là "thực sự chỉ là một chiếc bàn và vài thùng gỗ trong góc nhà máy rượu nhỏ của chúng tôi" - một phong cách chân thật và giản dị.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('d1239ea2-d792-43c7-06b1-dd65a8b5e269','vi','famous_for','Rượu thủ công, ít can thiệp, tôn vinh các giống nho và vùng ít được biết đến',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('d1239ea2-d792-43c7-06b1-dd65a8b5e269','zh-Hans','description','Yeah Wine是一家小规模的家族酒庄，由Sian和Andrew Dawson经营，他们亲手酿制、装瓶并贴标超过二十款葡萄酒，原料来自西澳的各地种植者。他们位于Wallcliffe路401号的质朴酒窖门店，"真的是我们小酒庄角落里的一个桌子和几个酒桶"，追求的是一种纯粹而不矫饰的风格。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('d1239ea2-d792-43c7-06b1-dd65a8b5e269','zh-Hans','famous_for','手工酿造的天然葡萄酒，推崇小众品种和产区',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('d1bf0d17-ae35-b32c-7f8a-be3b7ff4c043','vi','description','House of Cards là một nhà máy rượu vang hữu cơ được chứng nhận, nằm trên con đường Caves Road nổi tiếng ở đầu phía bắc của Margaret River, do Travis và Elizabeth Wray sở hữu và điều hành. Tại đây, bạn có thể thưởng thức rượu vang thủ công chỉ với $15 trong khi ngắm nhìn cảnh quan thiên nhiên. Nhà hàng Chow''s Table phục vụ các bữa trưa gia đình phong cách Trung Hoa hiện đại và Malaysia, ngoài ra còn có khay phô mai và khu vui chơi cho trẻ em.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('d1bf0d17-ae35-b32c-7f8a-be3b7ff4c043','vi','famous_for','Rượu vang hữu cơ 100% chứng nhận, thủ công từ vườn nho riêng, từ đỏ đậm đến trắng sủi.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('d1bf0d17-ae35-b32c-7f8a-be3b7ff4c043','zh-Hans','description','House of Cards庄园位于著名的Caves Road上，是Margaret River北端的一家经过有机认证的单一葡萄园酒庄，由Travis和Elizabeth Wray夫妇亲自经营。在这里，您可以花费$15品尝手工酿造的葡萄酒，同时欣赏自然景观。酒庄内还有Chow''s Table餐厅，提供现代中式与马来风味的家庭式午餐。此外，还有芝士拼盘和儿童游乐场可供选择。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('d1bf0d17-ae35-b32c-7f8a-be3b7ff4c043','zh-Hans','famous_for','100%有机认证，手工酿造的单一葡萄园葡萄酒，从浓郁红酒到气泡白酒，全部来自自家葡萄园。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('d5df22ab-333e-2eed-e6e1-0c46091d5198','vi','description','Hay Shed Hill là một hầm rượu nổi tiếng tại Wilyabrup, thuộc vùng Margaret River, mở cửa hàng ngày để thưởng thức chỗ ngồi với các dòng rượu Chardonnay và Cabernet Sauvignon từ điền trang. Ngoài ra, còn có những trải nghiệm được tuyển chọn như buổi pha chế rượu và kết hợp rượu vang với sô cô la. Nhà hàng Rustico tại chỗ phục vụ thực đơn tapas chia sẻ đạt giải thưởng, kết hợp hoàn hảo với các dòng rượu của điền trang.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('d5df22ab-333e-2eed-e6e1-0c46091d5198','vi','famous_for','Chardonnay và Cabernet Sauvignon; được xếp hạng Top 5 Red Star Winery trong Halliday Wine Companion 2025.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('d5df22ab-333e-2eed-e6e1-0c46091d5198','zh-Hans','description','Hay Shed Hill是位于Margaret River著名的Wilyabrup酒窖，每天开放，提供庄园Chardonnay和Cabernet Sauvignon的座位品鉴。这里还精心策划了独特体验，包括调配酒款课程及葡萄酒与巧克力搭配。其现场餐厅Rustico提供屡获殊荣的共享西班牙小吃套餐，搭配庄园美酒，令人难忘。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('d5df22ab-333e-2eed-e6e1-0c46091d5198','zh-Hans','famous_for','Chardonnay和Cabernet Sauvignon；2025年Halliday葡萄酒指南的五星红星酒庄。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('d83fd6d2-8bdd-989f-53e2-4e4d641d6f71','vi','description','Aravina Estate là một nhà máy rượu gia đình tại Margaret River, gần Yallingup, với cửa hầm rượu, nhà hàng ngồi xuống nhìn ra hồ và vườn nho, cùng với quán bia 8 Waves Brewing Co. của riêng mình. Nhân viên cửa hầm rượu sẽ hướng dẫn du khách thưởng thức sáu loại rượu vang trồng trong khuôn viên, với lựa chọn kết hợp với bữa ăn nhiều món.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('d83fd6d2-8bdd-989f-53e2-4e4d641d6f71','vi','famous_for','Rượu vang tự trồng kết hợp với ẩm thực bên hồ và nhà máy bia thủ công tại chỗ cùng phòng trưng bày lướt sóng.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('d83fd6d2-8bdd-989f-53e2-4e4d641d6f71','zh-Hans','description','Aravina Estate 是一座坐落于Yallingup附近的家族经营玛格丽特河酒庄，这里有一个品酒室、一个俯瞰湖泊和葡萄园的餐厅，以及自家的8 Waves Brewing Co.啤酒屋。品酒室的工作人员会带领参观者品尝六款庄园自种葡萄酒，并可选择搭配多道菜的美食体验。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('d83fd6d2-8bdd-989f-53e2-4e4d641d6f71','zh-Hans','famous_for','庄园自种葡萄酒与湖畔美食的完美搭配，并设有自酿啤酒厂和冲浪艺术馆。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('de8c34be-f131-04ad-2fbd-3013cfbd396b','vi','description','Hoạt động từ năm 1987 giữa rừng jarrah và marri của Yallingup, Deep Woods Estate mang đến những buổi thử rượu thư giãn với các loại rượu vang đã giành giải thưởng. Khách có thể mang theo bữa dã ngoại riêng để thưởng thức trên bãi cỏ cùng một ly rượu vang của điền trang. Dưới sự dẫn dắt của nhà sản xuất rượu vang danh tiếng Julian Langworthy, điền trang nổi tiếng với dòng Reserve Chardonnay và Cabernet Sauvignon.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('de8c34be-f131-04ad-2fbd-3013cfbd396b','vi','famous_for','Dòng Reserve Chardonnay và Cabernet Sauvignon đoạt giải, là một trong những nhà máy rượu vang được tôn vinh nhất Tây Úc (nhà sản xuất rượu Julian Langworthy, Nhà sản xuất rượu của năm Halliday Úc 2019)',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('de8c34be-f131-04ad-2fbd-3013cfbd396b','zh-Hans','description','自1987年以来，Deep Woods Estate坐落于Yallingup的jarrah和marri森林之间，为宾客提供轻松的品酒体验。您可以自带野餐，在草坪上与一杯精致的庄园葡萄酒一同享用。由著名酿酒师Julian Langworthy领导，该庄园以其获奖的Reserve Chardonnay和Cabernet Sauvignon而闻名。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('de8c34be-f131-04ad-2fbd-3013cfbd396b','zh-Hans','famous_for','屡获殊荣的Reserve Chardonnay和Cabernet Sauvignon，以及西澳大利亚最受赞誉的酒庄之一（首席酿酒师Julian Langworthy，2019年Halliday澳大利亚年度酿酒师）',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('e831283e-09c2-eaca-e1f3-c2f4f1f41308','vi','description','Một nhà máy rượu boutique ở Margaret River do nhà thám hiểm nho Dylan sáng lập, chọn lọc những lô nho đặc biệt từ khắp Tây Úc để tạo ra những chai rượu thú vị, dễ tiếp cận và thơm ngon. Cửa hầm rượu thư giãn cung cấp các buổi nếm thử 8-10 loại rượu, bao gồm các phiên bản giới hạn và các niên vụ cũ, với cảnh quan tuyệt đẹp, chào đón mang theo đồ picnic và chính sách thân thiện với thú cưng.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('e831283e-09c2-eaca-e1f3-c2f4f1f41308','vi','famous_for','Nổi tiếng với các loại rượu thủ công, can thiệp tối thiểu, sản xuất theo lô nhỏ, đặc biệt là Butter Barrels Chardonnay, đạt hạng nhất trong Giải thưởng People''s Choice của Top-Up Wines 2026, thể hiện sự đa dạng của thổ nhưỡng Tây Nam Úc.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('e831283e-09c2-eaca-e1f3-c2f4f1f41308','zh-Hans','description','这是一家位于玛格丽特河的精品酒庄，由葡萄探险家Dylan创立，精选西澳大利亚的优质葡萄，酿造出有趣、亲和且美味的葡萄酒。悠闲的酒窖门厅提供8至10款葡萄酒的坐式品尝，包括限量发行和陈年佳酿，伴随美丽的景观，同时欢迎自带野餐和宠物。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('e831283e-09c2-eaca-e1f3-c2f4f1f41308','zh-Hans','famous_for','以手工酿造、低干预的小批量葡萄酒闻名，尤其是他们的Butter Barrels Chardonnay，被评为2026年Top-Up Wines人民选择奖的第一名，完美展现了澳大利亚西南部的风土多样性。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('fa2f4f97-b0f9-2886-4ad6-6711ab28781d','vi','description','Brown Hill Estate là một nhà máy rượu gia đình nhỏ ở Rosa Brook, được điều hành trực tiếp bởi gia đình Bailey từ cửa hầm rượu trong một nhà kho xanh mộc mạc nằm ngay trong xưởng sản xuất, cho phép du khách quan sát quá trình làm rượu quanh năm. Các buổi nếm thử rượu được hướng dẫn bởi một thành viên trong gia đình, khám phá ba dòng rượu vang được chọn lọc kỹ càng, trồng tại vườn nho của họ.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('fa2f4f97-b0f9-2886-4ad6-6711ab28781d','vi','famous_for','Rượu vang đỏ chất lượng, giá phải chăng từ một vườn nho duy nhất, với tên gọi lấy cảm hứng từ các mỏ vàng nổi tiếng Kalgoorlie.',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('fa2f4f97-b0f9-2886-4ad6-6711ab28781d','zh-Hans','description','Brown Hill Estate是一家位于Rosa Brook的小型家族酒庄，由Bailey家族亲自经营。从一个质朴的绿色棚屋中打造的酒窖门口进入，游客可以全年观赏酿酒过程。品酒体验由家族成员亲自指导，深入了解他们精心挑选、手工筛选、自有葡萄园种植的三个系列葡萄酒。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
INSERT INTO winery_translation (winery_id, locale, field, value, machine_translated, reviewed, updated_at) VALUES ('fa2f4f97-b0f9-2886-4ad6-6711ab28781d','zh-Hans','famous_for','高性价比的单一庄园红酒（Shiraz和Cabernet），以著名的Kalgoorlie金矿命名。',true,false,now()) ON CONFLICT (winery_id, locale, field) DO UPDATE SET value=excluded.value, machine_translated=true, updated_at=now();
